(window.webpackJsonp=window.webpackJsonp||[]).push([[737],{707:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">events</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxEvents = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">events</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> pq=<span class=\\"hljs-keyword\\">new</span> PriorityQueue(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a-b)\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> maxDay=<span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-keyword\\">let</span> minDay=<span class=\\"hljs-literal\\">Infinity</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;events.length;i++){\\n    maxDay=<span class=\\"hljs-built_in\\">Math</span>.max(maxDay,events[i][<span class=\\"hljs-number\\">1</span>])\\n    minDay=<span class=\\"hljs-built_in\\">Math</span>.min(minDay,events[i][<span class=\\"hljs-number\\">0</span>])\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> aux=<span class=\\"hljs-built_in\\">Array</span>(maxDay+<span class=\\"hljs-number\\">1</span>).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span>[])\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [s,e] <span class=\\"hljs-keyword\\">of</span> events){\\n    aux[s].push(e)\\n  }\\n  <span class=\\"hljs-comment\\">// console.log(aux)</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=minDay;i&lt;=maxDay;i++){\\n    <span class=\\"hljs-comment\\">// if(!aux[i])continue</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;aux[i].length;j++){\\n      pq.insert(aux[i][j])\\n    }\\n    <span class=\\"hljs-keyword\\">while</span>(pq.size()&gt;<span class=\\"hljs-number\\">0</span> &amp;&amp; pq.peek()&lt;i){\\n      pq.pop()\\n    }\\n    <span class=\\"hljs-comment\\">// console.log(i,pq.size(),pq.peek())</span>\\n    <span class=\\"hljs-keyword\\">if</span>(pq.size()&gt;<span class=\\"hljs-number\\">0</span>){\\n      pq.pop()\\n      res++\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n\\n<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">PriorityQueue</span>(<span class=\\"hljs-params\\">compareFunction</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span> (!compareFunction) {\\n    compareFunction = <span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a, b</span>) =&gt;</span> a - b\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> heap = [<span class=\\"hljs-literal\\">null</span>]\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">swim</span>(<span class=\\"hljs-params\\">idx</span>) </span>{\\n    <span class=\\"hljs-keyword\\">if</span> (idx &lt; <span class=\\"hljs-number\\">2</span>) <span class=\\"hljs-keyword\\">return</span>\\n    <span class=\\"hljs-keyword\\">let</span> k = <span class=\\"hljs-built_in\\">Math</span>.floor(idx / <span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">if</span> (compareFunction(heap[idx], heap[k]) &lt; <span class=\\"hljs-number\\">0</span>) {\\n      swap(heap, idx, k)\\n      idx = k\\n      swim(idx)\\n    }\\n  }\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">sink</span>(<span class=\\"hljs-params\\">idx</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> k = <span class=\\"hljs-built_in\\">Math</span>.floor(idx * <span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">if</span> (k &gt;= heap.length) <span class=\\"hljs-keyword\\">return</span>\\n    <span class=\\"hljs-keyword\\">if</span> (k &lt; heap.length &amp;&amp; heap[k + <span class=\\"hljs-number\\">1</span>] &amp;&amp; compareFunction(heap[k + <span class=\\"hljs-number\\">1</span>], heap[k]) &lt; <span class=\\"hljs-number\\">0</span>) k++\\n    <span class=\\"hljs-keyword\\">if</span> (compareFunction(heap[k], heap[idx]) &lt; <span class=\\"hljs-number\\">0</span>) {\\n      swap(heap, idx, k)\\n      idx = k\\n      sink(idx)\\n    }\\n  }\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">swap</span>(<span class=\\"hljs-params\\">arr, i, j</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> temp = arr[i]\\n    arr[i] = arr[j]\\n    arr[j] = temp\\n  }\\n\\n  <span class=\\"hljs-keyword\\">this</span>.insert = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\">v</span>) </span>{\\n    heap.push(v)\\n    swim(heap.length - <span class=\\"hljs-number\\">1</span>)\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.pop = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    swap(heap, <span class=\\"hljs-number\\">1</span>, heap.length - <span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-keyword\\">let</span> v = heap.pop()\\n    sink(<span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-keyword\\">return</span> v\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.peek = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> heap[<span class=\\"hljs-number\\">1</span>]\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.size = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> heap.length - <span class=\\"hljs-number\\">1</span>\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.isEmpty = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> heap.length === <span class=\\"hljs-number\\">1</span>\\n  }\\n}\\n\\n</code></pre>\\n"],"titleSlug":"maximum-number-of-events-that-can-be-attended","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6570\u7ec4&nbsp;<code>events</code>\uff0c\u5176\u4e2d&nbsp;<code>events[i] = [startDay<sub>i</sub>, endDay<sub>i</sub>]</code>&nbsp;\uff0c\u8868\u793a\u4f1a\u8bae&nbsp;<code>i</code>&nbsp;\u5f00\u59cb\u4e8e&nbsp;<code>startDay<sub>i</sub></code>&nbsp;\uff0c\u7ed3\u675f\u4e8e&nbsp;<code>endDay<sub>i</sub></code>&nbsp;\u3002</p>\\n\\n<p>\u4f60\u53ef\u4ee5\u5728\u6ee1\u8db3&nbsp;<code>startDay<sub>i</sub>&nbsp;&lt;= d &lt;= endDay<sub>i</sub></code><sub>&nbsp;</sub>\u4e2d\u7684\u4efb\u610f\u4e00\u5929&nbsp;<code>d</code>&nbsp;\u53c2\u52a0\u4f1a\u8bae&nbsp;<code>i</code>&nbsp;\u3002\u6ce8\u610f\uff0c\u4e00\u5929\u53ea\u80fd\u53c2\u52a0\u4e00\u4e2a\u4f1a\u8bae\u3002</p>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de\u4f60\u53ef\u4ee5\u53c2\u52a0\u7684&nbsp;<strong>\u6700\u5927&nbsp;</strong>\u4f1a\u8bae\u6570\u76ee\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/02/16/e1.png\\" style=\\"height: 400px; width: 600px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>events = [[1,2],[2,3],[3,4]]\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u4f60\u53ef\u4ee5\u53c2\u52a0\u6240\u6709\u7684\u4e09\u4e2a\u4f1a\u8bae\u3002\\n\u5b89\u6392\u4f1a\u8bae\u7684\u4e00\u79cd\u65b9\u6848\u5982\u4e0a\u56fe\u3002\\n\u7b2c 1 \u5929\u53c2\u52a0\u7b2c\u4e00\u4e2a\u4f1a\u8bae\u3002\\n\u7b2c 2 \u5929\u53c2\u52a0\u7b2c\u4e8c\u4e2a\u4f1a\u8bae\u3002\\n\u7b2c 3 \u5929\u53c2\u52a0\u7b2c\u4e09\u4e2a\u4f1a\u8bae\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>events= [[1,2],[2,3],[3,4],[1,2]]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>events = [[1,4],[4,4],[2,2],[3,4],[1,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>events = [[1,100000]]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>events = [[1,1],[1,2],[1,3],[1,4],[1,5],[1,6],[1,7]]\\n<strong>\u8f93\u51fa\uff1a</strong>7\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= events.length &lt;= 10^5</code></li>\\n\\t<li><code>events[i].length == 2</code></li>\\n\\t<li><code>1 &lt;= events[i][0] &lt;= events[i][1] &lt;= 10^5</code></li>\\n</ul>\\n","title":"1353. \u6700\u591a\u53ef\u4ee5\u53c2\u52a0\u7684\u4f1a\u8bae\u6570\u76ee","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5","\u6392\u5e8f","\u7ebf\u6bb5\u6811"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1353"}')}}]);